from typing import List, Dict
from collections import defaultdict, deque
import heapq

# ---------- 1. BFS ----------
def bfs(graph: Dict[int, List[int]], start: int) -> Dict[int, int]:
    dist = {start: 0}
    queue = deque([start])
    while queue:
        node = queue.popleft()
        for nbr in graph[node]:
            if nbr not in dist:
                dist[nbr] = dist[node] + 1
                queue.append(nbr)
    return dist

# ---------- 2. DFS ----------
def dfs(graph, node, visited):
    visited.add(node)
    for nbr in graph[node]:
        if nbr not in visited:
            dfs(graph, nbr, visited)

def dfs_iter(graph, start):
    visited, stack = set(), [start]
    while stack:
        node = stack.pop()
        if node in visited:
            continue
        visited.add(node)
        for nbr in graph[node]:
            if nbr not in visited:
                stack.append(nbr)
    return visited

# ---------- 3. Number of Islands ----------
def num_islands(grid: List[List[str]]) -> int:
    if not grid:
        return 0
    rows, cols = len(grid), len(grid[0])
    count = 0
    def sink(r, c):
        if r < 0 or r >= rows or c < 0 or c >= cols or grid[r][c] != '1':
            return
        grid[r][c] = '0'
        sink(r+1,c); sink(r-1,c); sink(r,c+1); sink(r,c-1)
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == '1':
                count += 1
                sink(r, c)
    return count

# ---------- 4. Topo sort (Kahn) ----------
def topo_sort(num_nodes: int, edges: List[List[int]]) -> List[int]:
    graph = defaultdict(list)
    indegree = [0]*num_nodes
    for u, v in edges:
        graph[u].append(v)
        indegree[v] += 1
    queue = deque([n for n in range(num_nodes) if indegree[n] == 0])
    order = []
    while queue:
        node = queue.popleft()
        order.append(node)
        for nbr in graph[node]:
            indegree[nbr] -= 1
            if indegree[nbr] == 0:
                queue.append(nbr)
    return order if len(order) == num_nodes else []

# ---------- 5. Union-Find ----------
class UnionFind:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0]*n
        self.count = n
    def find(self, x):
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x
    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return False
        if self.rank[rx] < self.rank[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        if self.rank[rx] == self.rank[ry]:
            self.rank[rx] += 1
        self.count -= 1
        return True

# ---------- 6. Dijkstra ----------
def dijkstra(graph, start, n):
    dist = [float('inf')]*n
    dist[start] = 0
    heap = [(0, start)]
    while heap:
        d, node = heapq.heappop(heap)
        if d > dist[node]:
            continue
        for nbr, w in graph[node]:
            nd = d + w
            if nd < dist[nbr]:
                dist[nbr] = nd
                heapq.heappush(heap, (nd, nbr))
    return dist

# ---------- 7. Rotting oranges ----------
def rotting_oranges(grid):
    rows, cols = len(grid), len(grid[0])
    queue = deque()
    fresh = 0
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 2:
                queue.append((r,c,0))
            elif grid[r][c] == 1:
                fresh += 1
    minutes = 0
    while queue:
        r, c, t = queue.popleft()
        minutes = max(minutes, t)
        for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 1:
                grid[nr][nc] = 2
                fresh -= 1
                queue.append((nr,nc,t+1))
    return minutes if fresh == 0 else -1

# ---------- 8. Cycle detection ----------
def has_cycle_directed(graph, n):
    WHITE, GRAY, BLACK = 0, 1, 2
    color = [WHITE]*n
    def d(node):
        color[node] = GRAY
        for nbr in graph[node]:
            if color[nbr] == GRAY:
                return True
            if color[nbr] == WHITE and d(nbr):
                return True
        color[node] = BLACK
        return False
    return any(color[i] == WHITE and d(i) for i in range(n))

def has_cycle_undirected(graph, n):
    visited = set()
    def d(node, parent):
        visited.add(node)
        for nbr in graph[node]:
            if nbr not in visited:
                if d(nbr, node): return True
            elif nbr != parent:
                return True
        return False
    return any(node not in visited and d(node, -1) for node in range(n))

# ---------- 9. Bipartite ----------
def is_bipartite(graph):
    color = {}
    for start in range(len(graph)):
        if start in color:
            continue
        queue = deque([start])
        color[start] = 0
        while queue:
            node = queue.popleft()
            for nbr in graph[node]:
                if nbr not in color:
                    color[nbr] = color[node] ^ 1
                    queue.append(nbr)
                elif color[nbr] == color[node]:
                    return False
    return True

# ---------- 10. 0-1 BFS ----------
def zero_one_bfs(graph, start, n):
    dist = [float('inf')]*n
    dist[start] = 0
    dq = deque([start])
    while dq:
        node = dq.popleft()
        for nbr, w in graph[node]:
            if dist[node] + w < dist[nbr]:
                dist[nbr] = dist[node] + w
                if w == 0:
                    dq.appendleft(nbr)
                else:
                    dq.append(nbr)
    return dist

# ---------- 11. Bellman-Ford ----------
def bellman_ford(edges, n, start):
    dist = [float('inf')]*n
    dist[start] = 0
    for _ in range(n-1):
        for u, v, w in edges:
            if dist[u] != float('inf') and dist[u] + w < dist[v]:
                dist[v] = dist[u] + w
    for u, v, w in edges:
        if dist[u] != float('inf') and dist[u] + w < dist[v]:
            return None
    return dist

# ---------- 12. Kruskal ----------
def kruskal(n, edges):
    uf = UnionFind(n)
    total, used = 0, 0
    for w, u, v in sorted(edges):
        if uf.union(u, v):
            total += w
            used += 1
            if used == n-1:
                break
    return total

# ---------- 13. Floyd-Warshall ----------
def floyd_warshall(dist):
    n = len(dist)
    for k in range(n):
        for i in range(n):
            for j in range(n):
                dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
    return dist


# =================== TESTS ===================
def run():
    INF = float('inf')
    # BFS
    g = defaultdict(list, {0:[1,2],1:[0,3],2:[0,3],3:[1,2,4],4:[3]})
    assert bfs(g, 0) == {0:0,1:1,2:1,3:2,4:3}, bfs(g,0)

    # DFS connectivity
    visited = set(); dfs(g, 0, visited)
    assert visited == {0,1,2,3,4}
    assert dfs_iter(g, 0) == {0,1,2,3,4}

    # Islands
    grid = [list("11000"), list("11000"), list("00100"), list("00011")]
    assert num_islands(grid) == 3

    # Topo sort
    order = topo_sort(4, [[1,0],[2,0],[3,1],[3,2]])
    pos = {v:i for i,v in enumerate(order)}
    assert len(order) == 4 and pos[3] < pos[1] < pos[0] and pos[2] < pos[0]
    assert topo_sort(2, [[0,1],[1,0]]) == []  # cycle

    # Union-Find
    uf = UnionFind(5)
    uf.union(0,1); uf.union(1,2); uf.union(3,4)
    assert uf.count == 2
    assert uf.find(0) == uf.find(2) and uf.find(0) != uf.find(3)
    assert uf.union(0,2) is False  # redundant

    # Dijkstra
    wg = defaultdict(list, {0:[(1,4),(2,1)],1:[(3,1)],2:[(1,2),(3,5)],3:[]})
    assert dijkstra(wg, 0, 4) == [0,3,1,4]

    # Rotting oranges
    assert rotting_oranges([[2,1,1],[1,1,0],[0,1,1]]) == 4
    assert rotting_oranges([[2,1,1],[0,1,1],[1,0,1]]) == -1
    assert rotting_oranges([[0,2]]) == 0

    # Cycle detection
    dg = defaultdict(list, {0:[1],1:[2],2:[0]})
    assert has_cycle_directed(dg, 3) is True
    dag = defaultdict(list, {0:[1],1:[2],2:[]})
    assert has_cycle_directed(dag, 3) is False
    ug = defaultdict(list, {0:[1,2],1:[0,2],2:[0,1]})
    assert has_cycle_undirected(ug, 3) is True
    tree = defaultdict(list, {0:[1,2],1:[0],2:[0]})
    assert has_cycle_undirected(tree, 3) is False

    # Bipartite
    assert is_bipartite([[1,3],[0,2],[1,3],[0,2]]) is True   # even cycle
    assert is_bipartite([[1,2],[0,2],[0,1]]) is False        # triangle

    # 0-1 BFS
    zg = defaultdict(list, {0:[(1,0),(2,1)],1:[(2,1)],2:[(3,0)],3:[]})
    assert zero_one_bfs(zg, 0, 4) == [0,0,1,1]

    # Bellman-Ford (with negative edge, no neg cycle)
    edges = [(0,1,4),(0,2,5),(1,2,-3),(2,3,2)]
    assert bellman_ford(edges, 4, 0) == [0,4,1,3]
    # negative cycle
    negc = [(0,1,1),(1,2,-1),(2,0,-1)]
    assert bellman_ford(negc, 3, 0) is None

    # Kruskal
    medges = [(1,0,1),(2,1,2),(3,0,2),(4,2,3)]
    assert kruskal(4, medges) == 7   # 1+2+4

    # Floyd-Warshall
    d = [[0,3,INF],[INF,0,1],[INF,INF,0]]
    res = floyd_warshall([row[:] for row in d])
    assert res[0][2] == 4

    print("ALL GRAPH TEMPLATES PASSED")

run()
